            categories: [
                { name: "أشياء ذُكرت في سورة البقرة", nameEn: "Things mentioned in Surah Al-Baqarah", color: "yellow",
                    items: [{ar:"البقرة",en:"The Cow",verse:"ذَٰلِكَ الْكِتَابُ لَا رَيْبَ ۛ فِيهِ هُدًى لِّلْمُتَّقِينَ",ref:"2:2"},{ar:"التابوت",en:"The Ark",verse:"وَأَوْحَيْنَا إِلَىٰ أُمِّ مُوسَىٰ أَنْ أَرْضِعِيهِ فَإِذَا خِفْتِ عَلَيْهِ فَأَلْقِيهِ فِي الْيَمِّ وَلَا تَخَافِي وَلَا تَحْزَنِي إِنَّا رَادُّوهُ إِلَيْكِ وَجَاعِلُوهُ مِنَ الْمُرْسَلِينَ",ref:"القصص:7"},{ar:"العرش",en:"The Throne",verse:"اللَّهُ الَّذِي لَهُ الْعَرْشُ الْعَظِيمُ",ref:"40:7"},{ar:"المن والسلوى",en:"Manna and Quails",verse:"وَظَلَّلْنَا عَلَيْكُمُ الْغَمَامَ وَأَنْزَلْنَا عَلَيْكُمُ الْمَنَّ وَالسَّلْوَىٰ",ref:"2:57"}],
                    verse: {ayah:"إِنَّ اللَّهَ يَأْمُرُكُمْ أَن تَذْبَحُوا بَقَرَةً", en:"Indeed, Allah commands you to slaughter a cow.", ref:"2:67"}},
                { name: "ابتلاءات إبراهيم عليه السلام", nameEn: "Trials of Prophet Ibrahim (AS)", color: "green",
                    items: [{ar:"النار",en:"The Fire",verse:"وَاتَّقُوا النَّارَ الَّتِي وَقُودُهَا النَّاسُ وَالْحِجَارَةُ ۖ أُعِدَّتْ لِلْكَافِرِينَ",ref:"البقرة: 2:24"},{ar:"ذبح الابن",en:"Sacrifice of his son",verse:"فَلَمَّا بَلَغَ مَعَهُ السَّعْيَ قَالَ يَا بُنَيَّ إِنِّي أَرَىٰ فِي الْمَنَامِ أَنِّي أَذْبَحُكَ",ref:"37:102"},{ar:"هجرة الأهل",en:"Leaving family in desert",verse:"وَإِذْ هَجَرْتَ مِنْ أَهْلِكَ مَكَّةَ مُهَاجِرًا إِلَى اللَّهِ",ref:"60:1"},{ar:"بناء الكعبة",en:"Building the Ka'bah",verse:"وَإِذْ يَرْفَعُ إِبْرَاهِيمُ الْقَوَاعِدَ مِنَ الْبَيْتِ وَإِسْمَاعِيلُ رَبَّنَا تَقَبَّلْ مِنَّا إِنَّكَ أَنتَ السَّمِيعُ الْعَلِيمُ",ref:"البقرة:127"}],
                    verse: {ayah:"قُلْنَا يَا نَارُ كُونِي بَرْدًا وَسَلَامًا عَلَىٰ إِبْرَاهِيمَ", en:"We said: O fire, be coolness and safety upon Ibrahim.", ref:"21:69"}},
                { name: "معادن ذُكرت في القرآن", nameEn: "Metals mentioned in the Quran", color: "blue",
                    items: [{ar:"حديد",en:"Iron",verse:"وَأَنزَلْنَا الْحَدِيدَ فِيهِ بَأْسٌ شَدِيدٌ وَمَنَافِعُ لِلنَّاسِ",ref:"57:25"},{ar:"ذهب",en:"Gold",verse:"وَزُيِّنَ لَهُمُ الْحَيَاةُ الدُّنْيَا وَمَا فِيهَا مِنْ ذَهَبٍ وَفِضَّةٍ",ref:"9:34"},{ar:"فضة",en:"Silver",verse:"وَزُيِّنَ لَهُمُ الْحَيَاةُ الدُّنْيَا وَمَا فِيهَا مِنْ ذَهَبٍ وَفِضَّةٍ",ref:"9:34"},{ar:"نحاس",en:"Copper",verse:"وَإِذْ قَالَ مُوسَىٰ لِقَوْمِهِ إِنَّ اللَّهَ يَأْمُرُكُمْ أَنْ تَذْبَحُوا بَقَرَةً قَالُوا أَتَتَّخِذُنَا هُزُوًا قَالَ أَعُوذُ بِاللَّهِ أَنْ أَكُونَ مِنَ الْجَاهِلِينَ",ref:"البقرة:67"}],
                    verse: {ayah:"وَأَنزَلْنَا الْحَدِيدَ فِيهِ بَأْسٌ شَدِيدٌ وَمَنَافِعُ لِلنَّاسِ", en:"And We sent down iron, wherein is great military might and benefits for the people.", ref:"57:25"}},
                { name: "موضوعات سورة الرحمن", nameEn: "Themes of Surah Ar-Rahman", color: "purple",
                    items: [{ar:"علّم القرآن",en:"Taught the Quran",verse:"وَعَلَّمَ آدَمَ الْأَسْمَاءَ كُلَّهَا ثُمَّ عَرَضَهُمْ عَلَى الْمَلَائِكَةِ فَقَالَ أَنْبِئُونِي بِأَسْمَاءِ هَؤُلَاءِ إِن كُنتُمْ صَادِقِينَ",ref:"البقرة:31"},{ar:"مرج البحرين",en:"Two seas meeting",verse:"مَرَجَ الْبَحْرَيْنِ يَلْتَقِيَانِ بَيْنَهُمَا بَرْزَخٌ لَا يَبْغِيَانِ فَبِأَيِّ آلَاءِ رَبِّكُمَا تُكَذِّبَانِ",ref:"الرحمن:19-20"},{ar:"فبأي آلاء",en:"Which favors will you deny?",verse:"فَبِأَيِّ آلَاءِ رَبِّكُمَا تُكَذِّبَانِ مَلَكُوتَ السَّمَاوَاتِ وَالْأَرْضِ وَمَا بَيْنَهُمَا وَعَرْشُهُ الْعَظِيمُ",ref:"الرحمن:13-16"},{ar:"اللؤلؤ والمرجان",en:"Pearls and coral",verse:"فِيهِمَا فَاكِهَةٌ وَالنَّخْلُ ذَاتُ الْأَكْمَامِ وَالْحَبُّ ذُو الْعَصْفِ وَالرَّيْحَانُ فَبِأَيِّ آلَاءِ رَبِّكُمَا تُكَذِّبَانِ",ref:"الرحمن:68-69"}],
                    verse: {ayah:"الرَّحْمَٰنُ ۝ عَلَّمَ الْقُرْآنَ ۝ خَلَقَ الْإِنسَانَ ۝ عَلَّمَهُ الْبَيَانَ", en:"The Most Merciful. Taught the Quran. Created man. Taught him eloquence.", ref:"55:1-4"}}
            ]
